+    #[test]
+    fn test_apply_update_data_conflict_replace() {
+        let mut target = SimpleTarget::default();
+        target.tables.insert(
+            "t".to_owned(),
+            vec![vec![
+                SqliteValue::Integer(1),
+                SqliteValue::Text("actual".to_owned()),
+            ]],
